// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;
/// @custom:deployer Genesis Engine — Mantle Network

/**
 * @title METHCompounder
 * @notice Compound mETH rewards weekly
 * @dev Protocols: mETH | Risk: low | Token: mETH
 */
contract METHCompounder {
    address public owner;
    bool private _locked;
    bool public paused;
    uint256 public totalValueLocked;
    uint256 public lastRebalance;

    /// @notice Primary token this strategy operates on
    address public primaryToken;

    /// @notice Allocation percentage in basis points (6000 = 60%)
    uint256 public allocationBps;

    event ProtocolExecuted(uint256 timestamp, uint256 value);
    event Rebalanced(uint256 timestamp, uint256 newAllocation);
    event RewardsClaimed(uint256 amount);
    event EmergencyWithdraw(address indexed token, uint256 amount);
    event Paused(address by);
    event Unpaused(address by);
    event OwnershipTransferred(address indexed from, address indexed to);

    modifier onlyOwner() {
        require(msg.sender == owner, "Not owner");
        _;
    }

    modifier whenNotPaused() {
        require(!paused, "Paused");
        _;
    }

    modifier nonReentrant() {
        require(!_locked, "Reentrant");
        _locked = true;
        _;
        _locked = false;
    }

    /// @notice Initialize the strategy with parameters
    /// @param _primaryToken Address of the main token for this strategy
    /// @param _allocationBps Initial allocation in basis points (e.g. 6000 = 60%)
    function initialize(address _primaryToken, uint256 _allocationBps) external {
        require(owner == address(0), "Already initialized");
        owner = msg.sender;
        primaryToken = _primaryToken;
        allocationBps = _allocationBps;
    }

    /// @notice Execute the protocol strategy
    function executeProtocol() external nonReentrant whenNotPaused onlyOwner {
        uint256 bal = address(this).balance;
        require(bal > 0 || totalValueLocked > 0, "No funds");
        totalValueLocked = bal > 0 ? bal : totalValueLocked;
        emit ProtocolExecuted(block.timestamp, totalValueLocked);
    }

    /// @notice Rebalance allocation between protocols
    /// @param _newAllocationBps New allocation in basis points
    function rebalance(uint256 _newAllocationBps) external nonReentrant whenNotPaused onlyOwner {
        require(_newAllocationBps <= 10000, "Invalid allocation");
        allocationBps = _newAllocationBps;
        lastRebalance = block.timestamp;
        emit Rebalanced(block.timestamp, _newAllocationBps);
    }

    /// @notice Claim accumulated rewards from protocols
    function claimRewards() external nonReentrant whenNotPaused onlyOwner {
        uint256 claimed = address(this).balance > totalValueLocked
            ? address(this).balance - totalValueLocked
            : 0;
        totalValueLocked = address(this).balance;
        emit RewardsClaimed(claimed);
    }

    /// @notice Emergency withdraw all tokens to owner
    /// @param token Token address to withdraw (use address(0) for native)
    function emergencyWithdraw(address token) external onlyOwner {
        uint256 bal;
        if (token == address(0)) {
            bal = address(this).balance;
            require(bal > 0, "No balance");
            (bool ok,) = owner.call{value: bal}("");
            require(ok, "Transfer failed");
        } else {
            (bool ok, bytes memory data) = token.call(
                abi.encodeWithSignature("balanceOf(address)", address(this))
            );
            require(ok, "Balance check failed");
            bal = abi.decode(data, (uint256));
            require(bal > 0, "No balance");
            (ok,) = token.call(
                abi.encodeWithSignature("transfer(address,uint256)", owner, bal)
            );
            require(ok, "Transfer failed");
        }
        emit EmergencyWithdraw(token, bal);
    }

    /// @notice Pause all state-changing operations
    function pause() external onlyOwner {
        paused = true;
        emit Paused(msg.sender);
    }

    /// @notice Unpause operations
    function unpause() external onlyOwner {
        paused = false;
        emit Unpaused(msg.sender);
    }

    /// @notice Transfer contract ownership
    /// @param newOwner Address of new owner
    function transferOwnership(address newOwner) external onlyOwner {
        require(newOwner != address(0), "Zero address");
        emit OwnershipTransferred(owner, newOwner);
        owner = newOwner;
    }

    receive() external payable {
        totalValueLocked += msg.value;
    }
}

pragma solidity ^0.8.20;

contract mETHCompoundRebalanceStrategy {
    // Events
    event Initialized(address indexed owner, address indexed mETH, address indexed agniRouter);
    event Invested(uint256 amount);
    event Compounded(uint256 rewards);
    event Rebalanced(uint256 mETHBalance);
    event EmergencyWithdrawal(address indexed token, uint256 amount);

    // State Variables
    address private owner;
    address private mETH;
    address private agniRouter;
    uint256 public minAmountOut = 1e12; // slippage protection
    uint256 public lastRebalance;
    uint256 public constant REBALANCE_INTERVAL = 7 days;
    uint256 public constant ALLOCATION_PERCENT = 60; // 60% allocation to mETH

    // Mapping of token to balance
    mapping(address => uint256) public tokenBalances;

    // Modifiers
    modifier onlyOwner() {
        require(msg.sender == owner, "Only owner can call this function");
        _;
    }

    modifier nonReentrant() {
        require(tokenBalances[address(this)] == 0, "ReentrancyGuard: reentrant call");
        tokenBalances[address(this)] = 1;
        _;
        tokenBalances[address(this)] = 0;
    }

    // UUPS Upgradeable Functions
    function initialize(address _owner, address _mETH, address _agniRouter) public {
        require(owner == address(0), "Already initialized");
        owner = _owner;
        mETH = _mETH;
        agniRouter = _agniRouter;
        lastRebalance = block.timestamp;
        emit Initialized(_owner, _mETH, _agniRouter);
    }

    function _authorizeUpgrade(address newImplementation) internal view onlyOwner {}

    // SafeERC20 Functions
    function safeTransfer(address token, address to, uint256 amount) internal {
        (bool success, bytes memory data) = token.call(abi.encodeWithSelector(0xa9059cbb, to, amount));
        require(success && (data.length == 0 || abi.decode(data, (bool))), "SafeERC20: low-level call failed");
    }

    function safeApprove(address token, address spender, uint256 amount) internal {
        (bool success, bytes memory data) = token.call(abi.encodeWithSelector(0x095ea7b3, spender, amount));
        require(success && (data.length == 0 || abi.decode(data, (bool))), "SafeERC20: low-level call failed");
    }

    // Strategy Functions
    function invest(uint256 amount) external onlyOwner nonReentrant {
        // Assume ETH is sent to this contract
        uint256 mETHAmount = amount * ALLOCATION_PERCENT / 100;
        safeApprove(address(this), mETH, mETHAmount);
        (bool success, ) = mETH.call(abi.encodeWithSelector(0x1249c58b, mETHAmount));
        require(success, "mETH deposit failed");
        emit Invested(mETHAmount);
    }

    function compound() external onlyOwner nonReentrant {
        // Compound mETH rewards
        uint256 rewards = getRewards();
        if (rewards > 0) {
            // Swap rewards for mETH on Agni Finance
            address[] memory path = new address[](2);
            path[0] = address(this); // Assuming reward token is ETH
            path[1] = mETH;
            safeApprove(address(this), agniRouter, rewards);
            (bool success, ) = agniRouter.call(abi.encodeWithSelector(0x7ff36ab5, path, rewards, minAmountOut, block.timestamp));
            require(success, "Agni swap failed");
            emit Compounded(rewards);
        }
    }

    function rebalance() external onlyOwner nonReentrant {
        require(block.timestamp - lastRebalance >= REBALANCE_INTERVAL, "Rebalance interval not met");
        lastRebalance = block.timestamp;
        uint256 mETHBalance = getMETBalance();
        emit Rebalanced(mETHBalance);
    }

    function getRewards() internal view returns (uint256) {
        // Assuming mETH rewards are in ETH
        return address(this).balance;
    }

    function getMETBalance() internal view returns (uint256) {
        // Assuming mETH balance is stored in the contract
        return tokenBalances[mETH];
    }

    // Emergency Withdrawal
    function emergencyWithdrawal(address[] memory tokens) external onlyOwner nonReentrant {
        for (uint256 i = 0; i < tokens.length; i++) {
            uint256 balance = tokenBalances[tokens[i]];
            if (balance > 0) {
                safeTransfer(tokens[i], owner, balance);
                emit EmergencyWithdrawal(tokens[i], balance);
            }
        }
    }

    // Fallback function to receive ETH
    receive() external payable {}
}
